function buildContext(){
  var s=state;
  var top5=s.u.slice(0,5).map(function(u){
    var paris=s.a.filter(function(h){return h.n===u.n;});
    var profit=paris.reduce(function(a,h){return a+(h.win?(h.m*h.cote)-h.m:-h.m);},0);
    return u.n+'('+(profit>=0?'+':'')+profit.toFixed(0)+'€)';
  }).join(',');
  var totalProfit=s.a.reduce(function(a,h){return a+(h.win?(h.m*h.cote)-h.m:-h.m);},0);
  var cap=Object.values(s.b).reduce(function(a,v){var n=parseFloat(v);return a+(isNaN(n)?0:n);},0);
  var today=new Date();var dateStr=today.toLocaleDateString('fr-FR');
  var dayNames=['Dimanche','Lundi','Mardi','Mercredi','Jeudi','Vendredi','Samedi'];
  var dayName=dayNames[today.getDay()];
  return 'Tu es un assistant paris sportifs. Nous sommes le '+dayName+' '+dateStr+'. IMPORTANT: tout match dont la date est AVANT ce jour est TERMINE - ne jamais le presenter comme futur. REGLES: 1) Jamais de redirection ou "je n ai pas acces". 2) Max 2-3 phrases directes, sauf si on te demande d analyser ton bilan/tes stats: la fais 4 a 6 phrases avec les chiffres. 3) Si info via web dis-la directement. 4) Pas de markdown. 5) Si on te demande un match passe, donne le resultat si tu le sais. Bankroll:'+cap.toFixed(0)+'€ profit:'+totalProfit.toFixed(0)+'€ equipes:'+top5+'.'+_g45BilanForAI();
}
function _g45BilanForAI(){
  try{
    var a=(typeof state!=='undefined'&&state.a)||[]; if(!a.length) return '';
    function prof(h){ return h.win?((h.m*h.cote)-h.m):(-(+h.m||0)); }
    var n=a.length, wins=0, stake=0, profit=0, bySport={}, byBk={};
    a.forEach(function(h){ if(h.win)wins++; stake+=(+h.m||0); var pp=prof(h); profit+=pp; var sp=h.sport||'?'; bySport[sp]=(bySport[sp]||0)+pp; var bk=h.b||'?'; byBk[bk]=(byBk[bk]||0)+pp; });
    var wr=n?Math.round(wins/n*100):0, roi=stake?Math.round(profit/stake*100):0;
    function top(o,dir){ var k=null,v=null; Object.keys(o).forEach(function(x){ if(v==null||(dir>0?o[x]>v:o[x]<v)){v=o[x];k=x;} }); return k!=null?{k:k,v:v}:null; }
    var bSp=top(bySport,1), wSp=top(bySport,-1), bBk=top(byBk,1);
    var stN=0, stW=null; for(var i=0;i<a.length;i++){ var w=!!a[i].win; if(stW==null){stW=w;stN=1;} else if(w===stW){stN++;} else break; }
    function bn(k){ try{ return bki(k).n; }catch(e){ return k; } }
    var parts=[];
    parts.push('Stats bilan reelles: '+n+' paris, reussite '+wr+'%, ROI '+roi+'%, profit '+(profit>=0?'+':'')+profit.toFixed(0)+'EUR, mises totales '+stake.toFixed(0)+'EUR');
    if(bSp) parts.push('meilleur sport '+bSp.k+'('+(bSp.v>=0?'+':'')+bSp.v.toFixed(0)+'EUR)');
    if(wSp&&(!bSp||wSp.k!==bSp.k)) parts.push('pire sport '+wSp.k+'('+(wSp.v>=0?'+':'')+wSp.v.toFixed(0)+'EUR)');
    if(bBk) parts.push('meilleur bookmaker '+bn(bBk.k)+'('+(bBk.v>=0?'+':'')+bBk.v.toFixed(0)+'EUR)');
    if(stN>0) parts.push('serie en cours '+stN+' '+(stW?'gagnes':'perdus'));
    var last=a.slice(0,3).map(function(h){ return (h.sport||'')+' '+(h.n||h.target||'?')+' @'+(+h.cote||0).toFixed(2)+' '+(h.win?'gagne':'perdu'); });
    if(last.length) parts.push('3 derniers: '+last.join(' | '));
    return ' '+parts.join('. ')+'.';
  }catch(e){ return ''; }
}
function buildContextWithParams() {
  var base = buildContext();
  var extras = [];
  if (_chatParams.equipe) extras.push('Équipe focus: '+_chatParams.equipe);
  if (_chatParams.lieu !== 'both') extras.push('Mode favori: '+(_chatParams.lieu==='domicile'?'Domicile':'Extérieur'));
  if (_chatParams.types.length) extras.push('Types de paris à privilégier: '+_chatParams.types.join(', '));
  if (_chatParams.champOnly) extras.push('Analyse uniquement les matchs de championnat, exclure Coupes et amicaux');
  if (extras.length) base += ' PRÉFÉRENCES UTILISATEUR: '+extras.join('. ')+'.';
  return base;
}

async function sendChat(){
  var inp=$i('chat-input');
  var msg=inp?inp.value.trim():'';
  if(!msg)return;
  var key=getGeminiKey();
  if(!key){chatBubble('assistant','Configure ta cle Groq dans Outils.');return;}
  inp.value='';
  chatBubble('user',msg);
  _chatHistory.push({role:'user',content:msg});

  /* Indicateur de frappe */
  var box=$i('chat-messages');
  var typing=document.createElement('div');
  typing.id='chat-typing';
  typing.style.cssText='display:flex;justify-content:flex-start;';
  typing.innerHTML='<div style="padding:9px 13px;border-radius:14px 14px 14px 4px;background:var(--s2);color:var(--t3);font-size:12px;">…</div>';
  if(box){box.appendChild(typing);box.scrollTop=box.scrollHeight;}

  try{
    /* Recherche Tavily si question d'actu */
    var needsWeb=/match|résultat|score|classement|ligue|champion|derby|finale|vainqueur|transfert|blessé|compo|prochain|dernier|hier|aujourd|semaine|récent|actuell|2025|2026|nba|nfl|mlb|nhl|dodgers|lakers|yankees|chelsea|arsenal|psg|real|barça|liga|premier|bundesliga/i.test(msg);
    var webCtx='';var webFound=false;
    if(needsWeb&&getTavilyKey()){var searchResult=await searchTavily(msg);if(searchResult){webCtx=searchResult;webFound=true;}}
    var sysPrompt=webFound
      ?'Tu as ces infos web. Cite uniquement ce qui est confirmé. Si le score exact n est pas dans les infos, dis juste qui a gagné. 1-2 phrases en français, pas de supposition: '+webCtx
      :buildContextWithParams();
    var messages=[{role:'system',content:sysPrompt},{role:'user',content:msg}];
    var r=await fetch('https://api.groq.com/openai/v1/chat/completions',{
      method:'POST',
      headers:{'Content-Type':'application/json','Authorization':'Bearer '+key},
      body:JSON.stringify({model:'llama-3.3-70b-versatile',messages:messages,temperature:0.3,max_tokens:400})
    });
    var d=await r.json();
    var t=document.getElementById('chat-typing');if(t)t.remove();
    if(d.error)throw new Error(d.error.message);
    var reply=d.choices[0].message.content.trim();
    /* Retirer les citations [1][2] de compound-beta */
    reply=reply.replace(/\[\d+\]/g,'').trim();
    _chatHistory.push({role:'assistant',content:reply});
    chatBubble('assistant',reply);
  }catch(e){
    var t=document.getElementById('chat-typing');if(t)t.remove();
    chatBubble('assistant','Erreur : '+e.message);
  }
}

