  $i('edit-target').value=h.target||'';
  $i('edit-equipe').value=h.n||'';
  $i('edit-cote').value=h.cote||'';
  $i('edit-mise').value=h.m||'';
  $i('edit-sport').value=h.sport||'';
  $i('edit-comp').value=h.comp||'';
  $i('edit-type').value=h.type||'';
  $i('edit-bk').value=h.b||'';
  $i('edit-date').value=h.date||'';
