  var h=state.h[idx];
  h.target=$i('edit-target').value.trim();
  h.n=$i('edit-equipe').value.trim();
  h.cote=parseFloat($i('edit-cote').value)||h.cote;
  h.m=parseFloat($i('edit-mise').value)||h.m;
