        var nKey='n_'+Math.random().toString(36).substr(2,6); _usMatchCache[nKey]={sport:'🏒',h:hName,a:aName,hs:g.homeTeam.score,as:g.awayTeam.score,d:d3.toISOString().split('T')[0]};
        var nqlqs=window._nhlQuickStats||['O5.5','O6.5','BTS'];
