  'Allsvenskan': '🇸🇪',
  'Ekstraklasa': '🇵🇱',
  'Premier League': '🏴󠁧󠁢󠁥󠁮󠁧󠁿',
  'Primera Division': '🇪🇸',
  'Serie A': '🇮🇹',
