function _urlB64ToU8(base64){
  var pad='='.repeat((4-base64.length%4)%4);
  var b=(base64+pad).replace(/-/g,'+').replace(/_/g,'/');
  var raw=atob(b), arr=new Uint8Array(raw.length);
  for(var i=0;i<raw.length;i++) arr[i]=raw.charCodeAt(i);
  return arr;
}

