(function(){
  function _initNotif(){
    try{
      if(document.getElementById('notif-panel')) renderNotifPanel();
      var p=g45NotifPrefs();
      if(p.enabled && 'serviceWorker' in navigator){ navigator.serviceWorker.register('sw.js').then(function(){ g45SyncNotifs(); }).catch(function(){}); }
    }catch(e){}
  }
  if(document.readyState==='loading') document.addEventListener('DOMContentLoaded', _initNotif); else _initNotif();
})();

/* ═══════════ Résumé de match dépliable dans Saison (terrain + stats, façon Mondial) ═══════════ */
async function toggleSaisonMatchDetail(rowEl){
  var el = rowEl && rowEl.nextElementSibling;
  if(!el || el.className!=='smd-panel') return;
  var eventId = rowEl.getAttribute('data-eid')||'';
  var league = rowEl.getAttribute('data-lg')||'';
  if(el.getAttribute('data-open')==='1'){
    el.style.display='none'; el.innerHTML=''; el.setAttribute('data-open','0');
    if(el._refresh){ clearInterval(el._refresh); el._refresh=null; }
    return;
  }
  try{ var others=document.querySelectorAll('.smd-panel'); for(var i=0;i<others.length;i++){ if(others[i]!==el){ others[i].style.display='none'; others[i].innerHTML=''; others[i].setAttribute('data-open','0'); if(others[i]._refresh){ clearInterval(others[i]._refresh); others[i]._refresh=null; } } } }catch(e){}
  el.style.display='block'; el.setAttribute('data-open','1');
  if(!el.id) el.id='smd-'+eventId;
  el.innerHTML='<div style="padding:14px;text-align:center;color:var(--t3);font-size:11px;">⏳ Chargement du résumé…</div>';
  if(!eventId){ el.innerHTML='<div style="padding:12px;color:var(--t3);font-size:11px;text-align:center;">Résumé indisponible pour ce match.</div>'; return; }
  await _renderSaisonDetail(el, eventId, league);
}
// Rendu du détail Saisons — même traitement live que la Coupe du Monde, re-jouable pour le rafraîchissement
async function _renderSaisonDetail(el, eventId, league){
  try{
    var r=await fetch('https://site.api.espn.com/apis/site/v2/sports/soccer/'+(league||'eng.1')+'/summary?event='+eventId+'&lang=fr&region=fr');
    var data=await r.json();
    el._data=data;   // pour le sélecteur de marché (re-rendu sans re-fetch)
    var comp=(data.header&&data.header.competitions&&data.header.competitions[0])||{};
    var cps=comp.competitors||[];
    var home=cps.filter(function(c){return c.homeAway==='home';})[0]||cps[0]||{};
    var away=cps.filter(function(c){return c.homeAway==='away';})[0]||cps[1]||{};
    var homeId=(home.team&&home.team.id)||'', awayId=(away.team&&away.team.id)||'';
    var hN=(home.team&&(home.team.displayName||home.team.shortDisplayName))||'', aN=(away.team&&(away.team.displayName||away.team.shortDisplayName))||'';
    var hS=(home.score!=null?home.score:''), aS=(away.score!=null?away.score:'');
    var isLive=(typeof _isLive==='function')&&_isLive(data);

    // ── Bannière BUT (score augmenté depuis le dernier refresh) ──
    var goalBanner='';
    try{ if(typeof _liveScore==='function'){ var _sc=_liveScore(data); if(_sc){ if(isLive && el._lastScore!=null && _sc.total>el._lastScore){ if(typeof _g45EnsureGoalCSS==='function')_g45EnsureGoalCSS(); goalBanner=(typeof _goalBannerHtml==='function')?_goalBannerHtml(_sc):''; } el._lastScore=_sc.total; } } }catch(e){}

    var h='<div style="margin:4px 0 8px;padding:10px;background:rgba(0,0,0,.18);border-radius:10px;">';
    h+=goalBanner;
    // ── Bouton « Suivre ce match » → calendrier perso (HTML inline, sans dépendance) ──
    try{
      var _compName=''; try{ _compName=(data.header&&data.header.league&&(data.header.league.name||data.header.league.shortName))||''; }catch(_e){}
      var _sOn=false; try{ _sOn=(typeof g45SuivisHas==='function')&&g45SuivisHas(eventId); }catch(_e){}
      function _eaSv(x){return String(x==null?'':x).replace(/&/g,'&amp;').replace(/"/g,'&quot;');}
      h+='<div style="margin-bottom:8px;"><button onclick="g45SuiviBtn(this)" data-id="'+_eaSv(eventId)+'" data-date="'+_eaSv(comp.date||'')+'" data-home="'+_eaSv(hN)+'" data-away="'+_eaSv(aN)+'" data-comp="'+_eaSv(_compName||league||'')+'" data-league="'+_eaSv(league||'')+'" data-sport="soccer" '
        +'style="width:100%;box-sizing:border-box;font-size:12px;font-weight:800;padding:9px 12px;border-radius:9px;cursor:pointer;border:1.5px solid '+(_sOn?'rgba(30,215,96,.55)':'rgba(77,132,255,.55)')+';background:'+(_sOn?'rgba(30,215,96,.16)':'rgba(77,132,255,.12)')+';color:'+(_sOn?'#1ed760':'#7aa2ff')+';">'+(_sOn?'\u2605 Match suivi \u2014 dans ton calendrier':'\u2606 Suivre ce match (ajouter au calendrier)')+'</button></div>';
    }catch(_e){}
    // En live : on laisse le lecteur live afficher le score. Hors live : en-tête de score.
    if(!isLive) h+='<div style="display:flex;align-items:center;justify-content:center;gap:12px;font-size:13px;font-weight:800;color:var(--t1);margin-bottom:8px;"><span>'+hN+'</span><span style="color:var(--a);">'+hS+' - '+aS+'</span><span>'+aN+'</span></div>';
    // ── Blocs LIVE (vides automatiquement si match pas en cours) ──
    try{ if(typeof _liveBettingBlock==='function') h+=_liveBettingBlock(data, el.id); }catch(e){}
    try{ if(typeof _liveBetsBlock==='function'){ var _lb=_liveBetsBlock(data); if(_lb) h+=_lb; } }catch(e){}
    try{ if(typeof _liveBallBlock==='function') h+=_liveBallBlock(data); }catch(e){}
    try{ if(typeof _liveOddsBlock==='function') h+=_liveOddsBlock(data); }catch(e){}

    var added=false;
    // ── AVANT-MATCH (forme, bilan, probabilité) — uniquement pour les matchs à venir ──
    var _mstate=(comp.status&&comp.status.type&&comp.status.type.state)||'';
    if(_mstate==='pre' && !isLive){ try{ var _pm=_g45PreMatchBlock(data); if(_pm){ h+=_pm; added=true; } }catch(e){} }
    if(typeof _renderEspnMatchStats==='function'){ try{ var st=_renderEspnMatchStats(data, homeId, awayId, '#4d84ff'); if(st){ h+=st; added=true; } }catch(e){} }
    // Bouton stats avancées Sofascore (xG, tirs dans/hors surface…) — à la demande via Worker→RapidAPI
    try{
      function _eaAdv(x){return String(x==null?'':x).replace(/&/g,'&amp;').replace(/"/g,'&quot;');}
      var _advId='g45adv_'+(eventId||Math.random().toString(36).slice(2));
      h+='<div style="margin-top:8px;"><button onclick="g45LoadAdvStats(this)" data-date="'+_eaAdv(comp.date||'')+'" data-h="'+_eaAdv(hN)+'" data-a="'+_eaAdv(aN)+'" data-box="'+_advId+'" style="width:100%;box-sizing:border-box;font-size:12px;font-weight:800;padding:9px 12px;border-radius:9px;cursor:pointer;border:1.5px solid rgba(255,165,60,.5);background:rgba(255,165,60,.10);color:#ffb13d;">📊 Stats avancées (xG, tirs surface…)</button><div id="'+_advId+'" style="margin-top:8px;"></div></div>';
      var _tendId='g45tend_'+(eventId||Math.random().toString(36).slice(2));
      h+='<div style="margin-top:8px;"><button onclick="g45LoadTendance(this)" data-date="'+_eaAdv(comp.date||'')+'" data-h="'+_eaAdv(hN)+'" data-a="'+_eaAdv(aN)+'" data-box="'+_tendId+'" style="width:100%;box-sizing:border-box;font-size:12px;font-weight:800;padding:9px 12px;border-radius:9px;cursor:pointer;border:1.5px solid rgba(120,162,255,.5);background:rgba(120,162,255,.10);color:#8aa2ff;">📈 Tendance du public (cotes implicites)</button><div id="'+_tendId+'" style="margin-top:8px;"></div></div>';
      var _oddsId='g45odds_'+(eventId||Math.random().toString(36).slice(2));
      h+='<div style="margin-top:8px;"><button onclick="g45LoadOdds(this)" data-h="'+_eaAdv(hN)+'" data-a="'+_eaAdv(aN)+'" data-comp="'+_eaAdv(_compName||league||'')+'" data-box="'+_oddsId+'" style="width:100%;box-sizing:border-box;font-size:12px;font-weight:800;padding:9px 12px;border-radius:9px;cursor:pointer;border:1.5px solid rgba(46,204,113,.5);background:rgba(46,204,113,.12);color:#2ecc71;">💰 Cotes réelles (bookmakers FR)</button><div id="'+_oddsId+'" style="margin-top:8px;"></div></div>';
      var _moreId='g45more_'+(eventId||Math.random().toString(36).slice(2));
      h+='<div style="margin-top:8px;"><button onclick="g45LoadMoreOdds(this)" data-h="'+_eaAdv(hN)+'" data-a="'+_eaAdv(aN)+'" data-comp="'+_eaAdv(_compName||league||'')+'" data-box="'+_moreId+'" style="width:100%;box-sizing:border-box;font-size:12px;font-weight:800;padding:9px 12px;border-radius:9px;cursor:pointer;border:1.5px solid rgba(155,89,182,.5);background:rgba(155,89,182,.12);color:#b07cd6;">📋 Plus de marchés (O/U · BTTS · buteur)</button><div id="'+_moreId+'" style="margin-top:8px;"></div></div>';
      h+='<div style="margin-top:8px;"><button onclick="g45LoadMatchAI(this)" data-date="'+_eaAdv(comp.date||'')+'" data-h="'+_eaAdv(hN)+'" data-a="'+_eaAdv(aN)+'" data-comp="'+_eaAdv(_compName||league||'')+'" data-box="'+_oddsId+'ai" style="width:100%;box-sizing:border-box;font-size:12px;font-weight:800;padding:9px 12px;border-radius:9px;cursor:pointer;border:1.5px solid rgba(176,124,214,.5);background:rgba(176,124,214,.10);color:#b07cd6;">🧠 Analyse IA du match</button><div id="'+_oddsId+'ai" style="margin-top:8px;"></div></div>';
      added=true;
    }catch(e){}
    if(typeof _renderEspnMatchPitch==='function'){ try{ var pi=_renderEspnMatchPitch(data, '#4d84ff', function(x){return x;}); if(pi){ h+=pi; added=true; } }catch(e){} }
    try{ if(typeof _momentsTimeline==='function'){ var _mt=_momentsTimeline(data); if(_mt){ h+=_mt; added=true; } } }catch(e){}
    if(!added && !isLive) h+='<div style="font-size:11px;color:var(--t3);text-align:center;padding:6px;">Pas de détails (compo/stats) pour ce match.</div>';
    var _yr=''; try{ if(comp.date) _yr=new Date(comp.date).getFullYear()||''; }catch(e){}
    try{ if(typeof _videoBlock==='function') h+=_videoBlock(data, hN, aN, ('résumé '+_yr).trim()); }catch(e){}
    h+='</div>';
    el.innerHTML=h;
    if(_mstate==='pre'){ try{ _g45FillForm(el, 'soccer/'+league); _g45FillStandings(el, 'soccer/'+league); }catch(e){} }

    // ── Rafraîchissement auto pendant le match (toutes les 30 s) ──
    if(isLive){
      if(!el._refresh){ el._refresh=setInterval(function(){ if(el.getAttribute('data-open')!=='1'){ clearInterval(el._refresh); el._refresh=null; return; } if(document.hidden||el.offsetParent===null) return; _renderSaisonDetail(el, eventId, league); }, 30000); }
    } else if(el._refresh){ clearInterval(el._refresh); el._refresh=null; }
  }catch(e){ el.innerHTML='<div style="padding:12px;color:#ff6b6b;font-size:11px;text-align:center;">Résumé indisponible.</div>'; }
}
window.toggleSaisonMatchDetail=toggleSaisonMatchDetail;

