      if(!items.length) return;
      out+='<div style="font-size:10px;font-weight:800;color:#8aa0ff;text-transform:uppercase;letter-spacing:.5px;margin:10px 0 6px;">'+(_G45_SOFA_GRP[g.groupName]||g.groupName||'')+'</div>';
