        ln=(typeof ln==='number')?ln:(parseFloat(String(ln).replace(',','.'))||0);
        rn=(typeof rn==='number')?rn:(parseFloat(String(rn).replace(',','.'))||0);
        var tot=ln+rn, lp=tot>0?Math.round(ln/tot*100):50, rp=100-lp;
