      var _isWC=(slug==='fifa.world'||slug==='uefa.euro'||slug==='conmebol.america'||slug==='uefa.nations'||slug==='fifa.worldq.uefa');
      _btns='<div style="display:flex;gap:8px;margin-bottom:10px;flex-wrap:wrap;">'
