function g45CalNav(delta){ if(window._g45CalSlug) g45LoadCalendar(window._g45CalSlug, null, (window._g45CalOffset||0)+delta, window._g45CalSport); }
function g45CalDay(day){
  var box=document.getElementById('g45-cal-day'); if(!box) return;
  var evs=(window._g45CalByDay&&window._g45CalByDay[day])||[];
  if(!evs.length){ box.innerHTML=''; box.removeAttribute('data-day'); return; }
  if(box.getAttribute('data-day')===String(day)){ box.innerHTML=''; box.removeAttribute('data-day'); return; }
  box.setAttribute('data-day', String(day));
  function stOf(e){ return (e.status&&e.status.type&&e.status.type.state)||''; }
  evs=evs.slice().sort(function(a,b){ var ra=stOf(a)==='in'?0:1, rb=stOf(b)==='in'?0:1; if(ra!==rb) return ra-rb; return new Date(a.date)-new Date(b.date); });
  var _mdk=(window._g45CalY)+'-'+String((window._g45CalM||0)+1).padStart(2,'0')+'-'+String(day).padStart(2,'0');
  var _md=window._g45CalMd&&window._g45CalMd[_mdk];
  var hdr=(_md?'Journée '+_md+' · ':'')+new Date(evs[0].date).toLocaleDateString('fr-FR',{weekday:'long',day:'numeric',month:'long'});
  var h='<div style="font-size:9px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;color:#8aa0ff;margin-bottom:6px;">'+hdr+'</div>';
  evs.forEach(function(e){ h+=_g45MatchRow(e, window._g45CalSlug, window._g45CalSport); });
  box.innerHTML=h;
  _g45StartListRefresh();
}
window.g45LoadCalendar=g45LoadCalendar;
window.g45CalNav=g45CalNav;
window.g45CalDay=g45CalDay;

/* ───────────── CLASSEMENT (standings) foot + rugby — ESPN site v2 ───────────── */
/* Endpoint validé : site.api.espn.com/apis/v2/sports/{sport}/{slug}/standings?season=YYYY  → children[].standings.entries[] */
function _g45Stat(stats, names){
  if(!stats) return '';
  for(var i=0;i<names.length;i++){
    for(var j=0;j<stats.length;j++){
      var s=stats[j];
      if(s && (s.name===names[i] || s.type===names[i] || s.abbreviation===names[i])){
        return (s.displayValue!=null ? s.displayValue : (s.value!=null ? s.value : ''));
      }
    }
  }
  return '';
}
function g45ToggleStandings(slug, sportPath, btn){
  var box=document.getElementById('g45-standings'); if(!box) return;
  if(box.getAttribute('data-open')==='1'){
    box.innerHTML=''; box.removeAttribute('data-open');
    if(btn){ btn.style.background='rgba(240,176,32,.1)'; btn.style.color='#f0b020'; }
    return;
  }
  box.setAttribute('data-open','1');
  if(btn){ btn.style.background='#f0b020'; btn.style.color='#0d1220'; }
  g45LoadStandings(slug, sportPath, box);
}
async function g45LoadStandings(slug, sportPath, box){
  box.innerHTML='<div style="display:flex;align-items:center;gap:8px;padding:14px;color:var(--t3);font-size:11px;"><div style="width:12px;height:12px;border:2px solid rgba(240,176,32,.2);border-top-color:#f0b020;border-radius:50%;animation:spin .8s linear infinite;"></div>Chargement du classement…</div>';
  var now=new Date(), curY=now.getFullYear();
  var augY=(now.getMonth()>=7)?curY:curY-1; // saison européenne (août)
  var calYear=['bra.1','usa.1','arg.1','mex.1','rsa.1','nor.1','swe.1','fin.1','irl.1','jpn.1','kor.1','conmebol.libertadores','conmebol.america','242041'];
  var primary=(calYear.indexOf(slug)>=0)?curY:augY;
  if(sportPath==='rugby-league'||sportPath==='baseball'){ primary=curY; } // NRL / MLB = saison en année civile
  var seen={}, seasons=[primary,augY,curY,curY-1].filter(function(y){ if(seen[y])return false; seen[y]=1; return true; });
  try{
    var data=null, used=null;
    for(var i=0;i<seasons.length;i++){
      var r=await fetch('https://site.api.espn.com/apis/v2/sports/'+sportPath+'/'+slug+'/standings?season='+seasons[i]);
      if(!r.ok) continue;
      var j=await r.json();
      var groups=j.children||(j.standings?[j]:[]);
      var tot=0; groups.forEach(function(g){ tot+=(((g.standings&&g.standings.entries)||g.entries||[]).length); });
      if(tot>0){ data=j; used=seasons[i]; break; }
    }
    if(!data){ box.innerHTML='<div style="color:var(--t3);font-size:11px;text-align:center;padding:12px;">Classement indisponible pour cette compétition.</div>'; return; }
    box.innerHTML=g45RenderStandings(data, used, sportPath, slug);
  }catch(e){
    box.innerHTML='<div style="color:#ff6b6b;font-size:11px;text-align:center;padding:12px;">Erreur de chargement du classement.</div>';
  }
}
function _g45Hex2rgba(hex, a){ try{ hex=String(hex).replace('#',''); if(hex.length===3) hex=hex.split('').map(function(c){return c+c;}).join(''); var r=parseInt(hex.slice(0,2),16), g=parseInt(hex.slice(2,4),16), b=parseInt(hex.slice(4,6),16); return 'rgba('+r+','+g+','+b+','+a+')'; }catch(e){ return 'transparent'; } }
/* Zone de qualification → couleur+libellé, d'après la note ESPN (description). */
function _g45ZoneFromNote(desc){
  var d=String(desc||'').toLowerCase(); if(!d) return null;
  if(/eliminat/.test(d)) return null;
  if(/relegation.*(play|round)|releg.*barrag|barrag.*releg|relegation\/promotion/.test(d)) return {color:'#f0b020',label:'Barrage relégation'};
  if(/releg/.test(d)) return {color:'#ff4545',label:'Relégation'};
  if(/conference league/.test(d)) return {color:'#20c997',label:'Conference League'};
  if(/europa/.test(d)) return {color:'#f0862c',label:'Europa League'};
  if(/champions.*(qualif|play|round)|qualif.*champions/.test(d)) return {color:'#5aa0ff',label:'Barrage LDC'};
  if(/champions/.test(d)) return {color:'#1f6fff',label:'Ligue des Champions'};
  if(/wild ?card/.test(d)) return {color:'#5ad6a0',label:'Wild Card'};
  if(/clinch|playoff|postseason|division/.test(d)) return {color:'#1ed760',label:'Playoffs'};
  if(/play-?in/.test(d)) return {color:'#f0b020',label:'Play-in'};
  return null;
}
/* Repli par position : sports US (playoffs), rugby (finales), grands championnats de foot. */
function _g45ZoneByPos(slug, sportPath, pos, n){
  var C={ldc:'#1f6fff',bldc:'#5aa0ff',el:'#f0862c',ecl:'#20c997',barr:'#f0b020',rel:'#ff4545'};
  var us={
    basketball:function(p){ if(p<=6) return['#1ed760','Playoffs']; if(p<=10) return['#f0b020','Play-in']; return null; },
    hockey:function(p){ if(p<=8) return['#1ed760','Playoffs']; return null; },
    baseball:function(p){ if(p<=3) return['#1ed760','Playoffs']; return null; },
    football:function(p){ if(p<=7) return['#1ed760','Playoffs']; return null; }
  };
  if(us[sportPath]){ var zu=us[sportPath](pos); return zu?{color:zu[0],label:zu[1]}:null; }
  if(sportPath==='rugby-league'){ return pos<=8?{color:'#1ed760',label:'Finales (Top 8)'}:null; }
  if(sportPath==='rugby'){ return pos<=6?{color:'#1ed760',label:'Phase finale'}:null; }
  var maps={
    'fra.1':function(p){ if(p<=3) return[C.ldc,'Ligue des Champions']; if(p===4) return[C.bldc,'Barrage LDC']; if(p===5) return[C.el,'Europa League']; if(p===6) return[C.ecl,'Conference League']; if(p===n-2) return[C.barr,'Barrage relégation']; if(p>=n-1) return[C.rel,'Relégation']; return null; },
    'ger.1':function(p){ if(p<=4) return[C.ldc,'Ligue des Champions']; if(p===5) return[C.el,'Europa League']; if(p===6) return[C.ecl,'Conference League']; if(p===n-2) return[C.barr,'Barrage relégation']; if(p>=n-1) return[C.rel,'Relégation']; return null; },
    'eng.1':function(p){ if(p<=4) return[C.ldc,'Ligue des Champions']; if(p===5) return[C.el,'Europa League']; if(p===6) return[C.ecl,'Conference League']; if(p>=n-2) return[C.rel,'Relégation']; return null; },
    'esp.1':function(p){ if(p<=4) return[C.ldc,'Ligue des Champions']; if(p<=6) return[C.el,'Europa League']; if(p===7) return[C.ecl,'Conference League']; if(p>=n-2) return[C.rel,'Relégation']; return null; },
    'ita.1':function(p){ if(p<=4) return[C.ldc,'Ligue des Champions']; if(p<=6) return[C.el,'Europa League']; if(p===7) return[C.ecl,'Conference League']; if(p>=n-2) return[C.rel,'Relégation']; return null; }
  };
  var f=maps[slug]; if(!f) return null; var z=f(pos); return z?{color:z[0],label:z[1]}:null;
}
function g45RenderStandings(data, season, sportPath, slug){
  var groups=data.children||(data.standings?[data]:[]);
  if(!groups.length) return '<div style="color:var(--t3);font-size:11px;text-align:center;padding:12px;">Classement indisponible.</div>';
  var multi=groups.length>1;
  var usePct=(sportPath==='baseball'||sportPath==='basketball'||sportPath==='football'); // MLB/NBA/NFL = % victoires (NHL garde ses points)
  var seasLbl = season ? ((sportPath==='rugby-league'||sportPath==='baseball') ? String(season) : (season+'-'+String(season+1).slice(-2))) : '';
  var out='<div style="font-size:9px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;color:#8aa0ff;margin:2px 0 8px;">Classement'+(seasLbl?' · '+seasLbl:'')+'</div>';
  var legend={};
  groups.forEach(function(g){
    var entries=(g.standings&&g.standings.entries)||g.entries||[];
    if(!entries.length) return;
    entries=entries.slice().sort(function(a,b){
      var ra=parseFloat(_g45Stat(a.stats,['rank']))||999, rb=parseFloat(_g45Stat(b.stats,['rank']))||999;
      return ra-rb;
    });
    if(multi){ out+='<div style="font-size:11px;font-weight:800;color:var(--t1);margin:10px 0 4px;">'+(g.name||g.abbreviation||'Groupe')+'</div>'; }
    out+='<div style="overflow-x:auto;-webkit-overflow-scrolling:touch;">';
    out+='<table style="width:100%;border-collapse:collapse;font-size:11px;min-width:340px;">';
    out+='<thead><tr style="color:var(--t3);font-weight:700;">'
      +'<th style="text-align:left;padding:4px 3px;">#</th>'
      +'<th style="text-align:left;padding:4px 3px;">Équipe</th>'
      +'<th style="padding:4px 3px;">J</th><th style="padding:4px 3px;">V</th><th style="padding:4px 3px;">N</th><th style="padding:4px 3px;">D</th>'
      +'<th style="padding:4px 3px;">BP</th><th style="padding:4px 3px;">BC</th><th style="padding:4px 3px;">Diff</th>'
      +'<th style="padding:4px 3px;color:var(--t1);">'+(usePct?'% V':'Pts')+'</th></tr></thead><tbody>';
    entries.forEach(function(e,idx){
      var t=e.team||{}, st=e.stats||[];
      var _z=(e.note && _g45ZoneFromNote(e.note.description)) || _g45ZoneByPos(slug, sportPath, idx+1, entries.length);
      if(_z) legend[_z.label]=_z.color;
      var _bd=_z?('border-left:3px solid '+_z.color+';'):'border-left:3px solid transparent;';
      var _rowbg=_z?('background:'+_g45Hex2rgba(_z.color,.13)+';'):'';
      var logo=''; try{ logo=(t.logos&&t.logos[0]&&t.logos[0].href)||''; }catch(_){ }
      var nm=t.shortDisplayName||t.displayName||t.name||t.abbreviation||'?';
      var J=_g45Stat(st,['gamesPlayed']), V=_g45Stat(st,['wins','gamesWon']), N=_g45Stat(st,['ties','draws','gamesDrawn']), D=_g45Stat(st,['losses','gamesLost']);
      var BP=_g45Stat(st,['pointsFor']), BC=_g45Stat(st,['pointsAgainst']);
      var DF=_g45Stat(st,['pointDifferential']), PT=_g45Stat(st,['points']);
      var lastCol=PT!==''?PT:'-';
      if(usePct){
        var WP=parseFloat(_g45Stat(st,['winPercent']));
        if(!isNaN(WP)){ lastCol=(WP<=1?WP*100:WP).toFixed(1)+'%'; }
        else { var vv=parseFloat(V)||0, dd=parseFloat(D)||0; lastCol=(vv+dd>0)?((vv/(vv+dd)*100).toFixed(1)+'%'):'-'; }
      }
      out+='<tr style="border-top:1px solid rgba(255,255,255,.05);'+_rowbg+'">'
        +'<td style="padding:5px 3px 5px 7px;'+_bd+'color:var(--t3);font-weight:700;">'+(idx+1)+'</td>'
        +'<td style="padding:5px 3px;"><div style="display:flex;align-items:center;gap:6px;">'+(logo?'<img src="'+logo+'" style="width:16px;height:16px;object-fit:contain;" onerror="this.style.display=\'none\'">':'')+'<span style="color:var(--t1);font-weight:600;white-space:nowrap;">'+nm+'</span></div></td>'
        +'<td style="padding:5px 3px;text-align:center;color:var(--t2);">'+(J!==''?J:'-')+'</td>'
        +'<td style="padding:5px 3px;text-align:center;color:var(--t2);">'+(V!==''?V:'-')+'</td>'
        +'<td style="padding:5px 3px;text-align:center;color:var(--t2);">'+(N!==''?N:'-')+'</td>'
        +'<td style="padding:5px 3px;text-align:center;color:var(--t2);">'+(D!==''?D:'-')+'</td>'
        +'<td style="padding:5px 3px;text-align:center;color:var(--t3);">'+(BP!==''?BP:'-')+'</td>'
        +'<td style="padding:5px 3px;text-align:center;color:var(--t3);">'+(BC!==''?BC:'-')+'</td>'
        +'<td style="padding:5px 3px;text-align:center;color:var(--t2);">'+(DF!==''?DF:'-')+'</td>'
        +'<td style="padding:5px 3px;text-align:center;color:var(--t1);font-weight:800;">'+lastCol+'</td></tr>';
    });
    out+='</tbody></table></div>';
  });
  var legKeys=Object.keys(legend);
  if(legKeys.length){
    out+='<div style="display:flex;flex-wrap:wrap;gap:8px 12px;margin-top:8px;padding-top:7px;border-top:1px solid rgba(255,255,255,.06);">';
    legKeys.forEach(function(k){ out+='<span style="display:flex;align-items:center;gap:5px;font-size:9px;color:var(--t3);"><span style="display:inline-block;width:9px;height:9px;border-radius:2px;background:'+legend[k]+';"></span>'+k+'</span>'; });
    out+='</div>';
  }
  return out;
}
window.g45ToggleStandings=g45ToggleStandings;
window.g45LoadStandings=g45LoadStandings;

/* ───────────── CLASSEMENT INDIVIDUEL (buteurs/passeurs) foot — core API leaders ───────────── */
/* core API: .../leagues/{slug}/seasons/{year}/types/1/leaders → categories[goalsLeaders|assistsLeaders].leaders[]
   athlète + équipe sont des $ref en http:// → réécrits en https:// (whitelisté CSP) puis résolus + cachés. */
function _g45RefId(ref){ if(!ref) return ''; var m=ref.match(/\/(\d+)(?:\?|$)/); return m?m[1]:''; }
async function _g45ResolveRefs(refs){
  var uniq={}, out={};
  refs.forEach(function(p){ var id=_g45RefId(p[1]); if(!id) return; var key=p[0]+':'+id; if(!uniq[key]) uniq[key]={kind:p[0],ref:p[1],id:id}; });
  var toFetch=[];
  Object.keys(uniq).forEach(function(key){
    var cached=null; try{ cached=localStorage.getItem('g45esp_'+key.replace(':','_')); }catch(e){}
    if(cached){ out[key]=cached; } else { toFetch.push(uniq[key]); }
  });
  await Promise.all(toFetch.map(async function(u){
    try{
      var r=await fetch(u.ref.replace(/^http:/,'https:')); if(!r.ok) return;
      var d=await r.json();
      var val=(u.kind==='ath')?(d.displayName||d.shortName||d.fullName||''):(d.abbreviation||d.shortDisplayName||d.displayName||'');
      if(val){ out[u.kind+':'+u.id]=val; try{ localStorage.setItem('g45esp_'+u.kind+'_'+u.id, val); }catch(e){} }
    }catch(e){}
  }));
  return out;
}
function g45ToggleScorers(slug, sportPath, btn){
  var box=document.getElementById('g45-scorers'); if(!box) return;
  if(box.getAttribute('data-open')==='1'){
    box.innerHTML=''; box.removeAttribute('data-open');
    if(btn){ btn.style.background='rgba(77,132,255,.1)'; btn.style.color='#4d84ff'; }
    return;
  }
  box.setAttribute('data-open','1'); if(btn){ btn.style.background='#4d84ff'; btn.style.color='#fff'; }
  g45LoadScorers(slug, sportPath, box);
}
async function g45LoadScorers(slug, sportPath, box){
  box.innerHTML='<div style="display:flex;align-items:center;gap:8px;padding:14px;color:var(--t3);font-size:11px;"><div style="width:12px;height:12px;border:2px solid rgba(77,132,255,.2);border-top-color:#4d84ff;border-radius:50%;animation:spin .8s linear infinite;"></div>Chargement des buteurs…</div>';
  var now=new Date(), curY=now.getFullYear();
  var augY=(now.getMonth()>=7)?curY:curY-1;
  var calYear=['bra.1','usa.1','arg.1','mex.1','rsa.1','nor.1','swe.1','fin.1','irl.1','jpn.1','kor.1'];
  var primary=(calYear.indexOf(slug)>=0)?curY:augY;
  var seen={}, seasons=[primary,augY,curY].filter(function(y){ if(seen[y])return false; seen[y]=1; return true; });
  try{
    var lead=null, used=null;
    for(var i=0;i<seasons.length;i++){
      var r=await fetch('https://sports.core.api.espn.com/v2/sports/soccer/leagues/'+slug+'/seasons/'+seasons[i]+'/types/1/leaders');
      if(!r.ok) continue;
      var j=await r.json();
      var g=(j.categories||[]).filter(function(c){return c.name==='goalsLeaders';})[0];
      if(g && g.leaders && g.leaders.length){ lead=j; used=seasons[i]; break; }
    }
    if(!lead){ box.innerHTML='<div style="color:var(--t3);font-size:11px;text-align:center;padding:12px;">Classement des buteurs indisponible pour cette compétition.</div>'; return; }
    var cats=lead.categories||[];
    var goalsCat=cats.filter(function(c){return c.name==='goalsLeaders';})[0];
    var assistsCat=cats.filter(function(c){return c.name==='assistsLeaders';})[0];
    var goalTop=((goalsCat&&goalsCat.leaders)||[]).slice(0,10);
    var assistTop=((assistsCat&&assistsCat.leaders)||[]).slice(0,10);
    var refs=[];
    goalTop.concat(assistTop).forEach(function(L){
      if(L.athlete&&L.athlete.$ref) refs.push(['ath',L.athlete.$ref]);
      if(L.team&&L.team.$ref) refs.push(['team',L.team.$ref]);
    });
    var map=await _g45ResolveRefs(refs);
    function nameOf(L){ return map['ath:'+_g45RefId(L.athlete&&L.athlete.$ref)]||'?'; }
    function teamOf(L){ return map['team:'+_g45RefId(L.team&&L.team.$ref)]||''; }
    function listHtml(title, ico, arr){
      if(!arr.length) return '';
      var rows=arr.map(function(L,i){
        return '<div style="display:grid;grid-template-columns:20px 1fr auto auto;gap:8px;align-items:center;padding:5px 3px;border-top:1px solid rgba(255,255,255,.05);font-size:12px;">'
          +'<div style="color:var(--t3);font-weight:700;">'+(i+1)+'</div>'
          +'<div style="color:var(--t1);font-weight:600;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">'+nameOf(L)+'</div>'
          +'<div style="color:var(--t3);font-size:9px;">'+teamOf(L)+'</div>'
          +'<div style="color:var(--a);font-weight:800;min-width:24px;text-align:right;">'+(L.value!=null?Math.round(L.value):'')+'</div></div>';
      }).join('');
      return '<div style="margin-bottom:10px;"><div style="font-size:11px;font-weight:800;color:var(--t1);margin:6px 0 2px;">'+ico+' '+title+'</div>'+rows+'</div>';
    }
    var seasLbl = used ? (used+'-'+String(used+1).slice(-2)) : '';
    box.innerHTML='<div style="font-size:9px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;color:#4d84ff;margin:2px 0 8px;">⚽ Classement individuel'+(seasLbl?' · '+seasLbl:'')+'</div>'
      +listHtml('Meilleurs buteurs','🥇',goalTop)
      +listHtml('Meilleurs passeurs','🎯',assistTop);
  }catch(e){
    box.innerHTML='<div style="color:#ff6b6b;font-size:11px;text-align:center;padding:12px;">Erreur de chargement des buteurs.</div>';
  }
}
window.g45ToggleScorers=g45ToggleScorers;
window.g45LoadScorers=g45LoadScorers;
/* ─────────── Phase finale (bracket) Coupe du Monde / tournois à élimination ─────────── */
function g45ToggleBracket(slug, sportPath, btn){
  var box=document.getElementById('g45-bracket'); if(!box) return;
  if(box.getAttribute('data-open')==='1'){
    box.innerHTML=''; box.removeAttribute('data-open');
    if(btn){ btn.style.background='rgba(30,215,96,.1)'; btn.style.color='#1ed760'; }
    return;
  }
  box.setAttribute('data-open','1'); if(btn){ btn.style.background='#1ed760'; btn.style.color='#06210f'; }
  if(sportPath==='soccer') g45LoadBracket(slug, box);
  else _g45LoadUsBracket(slug, sportPath, box);
}
/* Bracket playoffs US (séries best-of-7) : regroupe les matchs en séries, classe par tour. */
async function _g45LoadUsBracket(slug, sportPath, box){
  box.innerHTML='<div style="display:flex;align-items:center;gap:8px;padding:14px;color:var(--t3);font-size:11px;"><div style="width:12px;height:12px;border:2px solid rgba(30,215,96,.2);border-top-color:#1ed760;border-radius:50%;animation:spin .8s linear infinite;"></div>Chargement des playoffs…</div>';
  function ea(s){return String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/"/g,'&quot;');}
  try{
    var now=new Date(), y=now.getFullYear();
    var W={basketball:['0412','0701'],hockey:['0412','0701'],baseball:['0928','1120'],football:['0108','0216'],'rugby-league':['0820','1015']}[sportPath]||['0401','0701'];
    async function fetchWin(yr){ try{ var r=await fetch('https://site.api.espn.com/apis/site/v2/sports/'+sportPath+'/'+slug+'/scoreboard?dates='+yr+W[0]+'-'+yr+W[1]+'&limit=1000&seasontype=3'); return r.ok?(await r.json()):null; }catch(e){ return null; } }
    var data=await fetchWin(y), evs=(data&&data.events)||[];
    if(!evs.length){ data=await fetchWin(y-1); evs=(data&&data.events)||[]; }
    evs=evs.filter(function(e){ var st=(e.season&&e.season.type); return st==null||st===3||st==='3'; });
    var series={};
    evs.forEach(function(e){
      var c=(e.competitions&&e.competitions[0])||{}, cps=c.competitors||[]; if(cps.length<2) return;
      var ids=cps.map(function(x){return String((x.team&&x.team.id)||'');}).filter(Boolean); if(ids.length<2) return;
      var sk=ids.slice().sort().join('-');
      if(!series[sk]) series[sk]={teams:{}, order:[], start:e.date, end:e.date};
      var s=series[sk], stx=(c.status&&c.status.type)||{};
      var td=new Date(e.date); if(td<new Date(s.start)) s.start=e.date; if(td>new Date(s.end)) s.end=e.date;
      cps.forEach(function(x){ var id=String((x.team&&x.team.id)||''); if(!id) return; if(!s.teams[id]){ s.teams[id]={t:x.team, wins:0}; s.order.push(id); } if((stx.completed||stx.state==='post') && x.winner===true) s.teams[id].wins++; });
    });
    var list=Object.keys(series).map(function(k){return series[k];});
    // Tour = 1 + nb de séries déjà terminées (avant le début de celle-ci) impliquant une des 2 équipes
    list.forEach(function(s){
      var prior=0;
      s.order.forEach(function(id){ var cnt=list.filter(function(o){ return o!==s && o.teams[id] && new Date(o.end) < new Date(s.start); }).length; if(cnt>prior) prior=cnt; });
      s.k=prior+1;
    });
    var maxK=list.length?Math.max.apply(null, list.map(function(s){return s.k;})):0;
    function roundName(k){ if(k===maxK) return '🏆 Finale'; if(k===maxK-1) return (sportPath==='basketball'||sportPath==='hockey'||sportPath==='football')?'Finale de conférence':'Demi-finale'; if(k===1) return '1er tour'; return k+'e tour'; }
    var byRound={};
    list.forEach(function(s){ (byRound[s.k]=byRound[s.k]||{n:roundName(s.k),items:[]}).items.push(s); });
    var rks=Object.keys(byRound).map(Number).sort(function(a,b){return a-b;});
    if(!rks.length){ box.innerHTML='<div style="color:var(--t3);font-size:11px;text-align:center;padding:14px;">🏟 Playoffs indisponibles.<br><span style="font-size:9px;color:#8aa0ff;">diag → '+evs.length+' matchs playoffs trouvés (sport='+sportPath+' lg='+slug+')</span></div>'; return; }
    if(!document.getElementById('g45brk-css')){
      var stl=document.createElement('style'); stl.id='g45brk-css';
      stl.textContent='.g45brk-wrap{overflow-x:auto;-webkit-overflow-scrolling:touch;padding-bottom:8px;}.g45brk{display:flex;align-items:stretch;padding:2px;}.g45brk-col{flex:1 1 0;min-width:150px;display:flex;flex-direction:column;padding:0 8px;}.g45brk-h{font-size:9px;font-weight:800;text-transform:uppercase;color:#1ed760;text-align:center;letter-spacing:.5px;padding:2px 0 8px;}.g45brk-body{flex:1;display:flex;flex-direction:column;justify-content:space-around;gap:8px;}.g45brk-card{background:rgba(255,255,255,.04);border:1px solid rgba(255,255,255,.09);border-radius:8px;overflow:hidden;}.g45brk-r{display:flex;align-items:center;gap:5px;padding:5px 8px;font-size:11px;}.g45brk-r+.g45brk-r{border-top:1px solid rgba(255,255,255,.06);}.g45brk-r img{width:16px;height:16px;object-fit:contain;flex-shrink:0;}.g45brk-nm{flex:1;font-weight:600;color:var(--t1);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;}.g45brk-sc{font-weight:800;color:var(--t1);min-width:14px;text-align:right;font-size:13px;}.g45brk-win .g45brk-nm,.g45brk-win .g45brk-sc{color:#1ed760;font-weight:800;}';
      document.head.appendChild(stl);
    }
    function card(s){
      function row(id){ var tm=s.teams[id], t=tm.t||{}; var logo=''; try{logo=(t.logos&&t.logos[0]&&t.logos[0].href)||t.logo||'';}catch(_){} var nm=t.shortDisplayName||t.abbreviation||t.displayName||'?'; var win=tm.wins>=4; return '<div class="g45brk-r'+(win?' g45brk-win':'')+'">'+(logo?'<img src="'+ea(logo)+'" onerror="this.style.display=\'none\'">':'')+'<span class="g45brk-nm">'+ea(nm)+'</span><span class="g45brk-sc">'+tm.wins+'</span></div>'; }
      return '<div class="g45brk-card">'+s.order.map(row).join('')+'</div>';
    }
    var html='<div style="font-size:9px;color:#8aa0ff;text-align:center;margin:2px 0 8px;font-weight:700;">🏟 PLAYOFFS (séries)</div><div class="g45brk-wrap"><div class="g45brk">';
    rks.forEach(function(k){ var col=byRound[k]; col.items.sort(function(a,b){return new Date(a.start)-new Date(b.start);}); html+='<div class="g45brk-col"><div class="g45brk-h">'+ea(col.n)+'</div><div class="g45brk-body">'+col.items.map(card).join('')+'</div></div>'; });
    html+='</div></div>';
    box.innerHTML=html;
  }catch(e){ box.innerHTML='<div style="color:#ff6b6b;font-size:11px;text-align:center;padding:12px;">Erreur playoffs.</div>'; }
}
// Reconstruit le vrai ordre de l'arbre à partir du câblage ESPN (placeholders "Round of 32 N Winner"…)
function _g45BrkBracketOrder(groups){
  try{
    function feed(ev, re){
      var c=(ev.competitions&&ev.competitions[0])||{}, out=[];
      (c.competitors||[]).forEach(function(x){
        var nm=(x.team&&(x.team.displayName||x.team.shortDisplayName||x.team.name))||'';
        var m=nm.match(re); if(m) out.push(parseInt(m[1],10));
      });
      return out;
    }
    function byDate(arr){ return (arr||[]).slice().sort(function(a,b){return new Date(a.date)-new Date(b.date);}); }
    function numMap(arr){ var m={}; byDate(arr).forEach(function(e,i){ m[i+1]=e; }); return m; }
    var g2=groups[2]&&groups[2].items, g3=groups[3]&&groups[3].items, g4=groups[4]&&groups[4].items, g5=groups[5]&&groups[5].items, g7=groups[7]&&groups[7].items;
    if(!g2||!g3||!g4||!g5||!g7) return null;
    if(g2.length<16||g3.length<8||g4.length<4||g5.length<2||!g7.length) return null;
    var r32=numMap(g2), r16=numMap(g3), qf=numMap(g4), sf=numMap(g5), finalEv=byDate(g7)[0];
    var ord={2:[],3:[],4:[],5:[],7:[finalEv]}, ok=true;
    function pushR16(n){ var e=r16[n]; if(!e){ok=false;return;} ord[3].push(e); var fs=feed(e,/Round of 32 (\d+)/i); if(fs.length<2){ok=false;return;} fs.forEach(function(g){ var ev=r32[g]; if(!ev){ok=false;return;} ord[2].push(ev); }); }
    function pushQF(n){ var e=qf[n]; if(!e){ok=false;return;} ord[4].push(e); var fs=feed(e,/Round of 16 (\d+)/i); if(fs.length<2){ok=false;return;} fs.forEach(pushR16); }
    function pushSF(n){ var e=sf[n]; if(!e){ok=false;return;} ord[5].push(e); var fs=feed(e,/Quarterfinal (\d+)/i); if(fs.length<2){ok=false;return;} fs.forEach(pushQF); }
    var ffs=feed(finalEv,/Semifinal (\d+)/i); if(ffs.length<2) return null;
    ffs.forEach(pushSF);
    if(!ok) return null;
    if(ord[2].length!==16||ord[3].length!==8||ord[4].length!==4||ord[5].length!==2) return null;
    return ord;
  }catch(e){ return null; }
}
/* Ordre officiel FIFA 2026 codé en dur (ESPN ne câble pas les 8es : "RD32 vs RD32").
   On reconnaît chaque 16e par ses 2 abréviations d'équipe et on le place dans l'arbre réel.
   Ordre construit en profondeur depuis la finale → connecteurs alignés (pas de croisement). */
function _g45BrkOfficial2026(groups, slug){
  try{
    if(!/fifa\.world/i.test(slug||'')) return null;
    var g2=groups[2]&&groups[2].items;
    if(!g2||g2.length<16) return null;
    function pairKey(e){
      var c=(e.competitions&&e.competitions[0])||{}, ab=[];
      (c.competitors||[]).forEach(function(x){ var a=(x.team&&(x.team.abbreviation||x.team.shortDisplayName||x.team.displayName))||''; if(a) ab.push(a.toUpperCase()); });
      return ab.slice().sort().join('|');
    }
    // 16es dans l'ordre d'affichage officiel (chaque paire adjacente = un 8e), d'après le tirage réel (Flashscore)
    var ORDER16=[['GER','PAR'],['FRA','SWE'],['RSA','CAN'],['NED','MAR'],['POR','CRO'],['ESP','AUT'],['USA','BIH'],['BEL','SEN'],['BRA','JPN'],['CIV','NOR'],['MEX','ECU'],['ENG','COD'],['ARG','CPV'],['AUS','EGY'],['SUI','ALG'],['COL','GHA']];
    var byPair={}; g2.forEach(function(e){ byPair[pairKey(e)]=e; });
    var ord2=[];
    for(var i=0;i<ORDER16.length;i++){
      var ev=byPair[ORDER16[i].slice().sort().join('|')];
      if(!ev) return null; // une affiche ne matche pas (équipes pas encore connues) → logique générique
      ord2.push(ev);
    }
    // On ne fournit que l'ordre des 16es : les tours suivants n'ont pas encore d'équipes côté ESPN
    // ("RD32 vs RD32"), ils s'alignent positionnellement tout seuls (tri par date en repli).
    return {2:ord2};
  }catch(e){ return null; }
}
async function g45LoadBracket(slug, box){
  box.innerHTML='<div style="display:flex;align-items:center;gap:8px;padding:14px;color:var(--t3);font-size:11px;"><div style="width:12px;height:12px;border:2px solid rgba(30,215,96,.2);border-top-color:#1ed760;border-radius:50%;animation:spin .8s linear infinite;"></div>Chargement de la phase finale…</div>';
  try{
    var now=new Date(), y=now.getFullYear();
    var r=await fetch('https://site.api.espn.com/apis/site/v2/sports/soccer/'+slug+'/scoreboard?dates='+y+'0601-'+y+'0731&limit=400');
    var data=r.ok?await r.json():null;
    var evs=(data&&data.events)||[];
    function classify(s){
      if(/third|3rd|petite final|place play/.test(s)) return {k:6,n:'🥉 Match pour la 3e place'};
      if(/final/.test(s) && !/semi|quarter|round of|1\/|eighth|last \d/.test(s)) return {k:7,n:'🏆 Finale'};
      if(/semi/.test(s)) return {k:5,n:'½ Demi-finales'};
      if(/quarter|1\/4/.test(s)) return {k:4,n:'¼ Quarts de finale'};
      if(/round of 16|1\/8|eighth|last 16/.test(s)) return {k:3,n:'8es de finale'};
      if(/round of 32|1\/16|last 32/.test(s)) return {k:2,n:'16es de finale'};
      return null;
    }
    function roundOf(e){
      var c=(e.competitions&&e.competitions[0])||{}, s='';
      try{ (c.notes||[]).forEach(function(n){ s+=' '+(n.headline||n.text||''); }); }catch(_e){}
      try{ s+=' '+((e.season&&(e.season.slug||e.season.name||(e.season.type&&e.season.type.name)))||''); }catch(_e){}
      try{ s+=' '+((c.type&&(c.type.text||c.type.abbreviation))||''); }catch(_e){}
      var byNote=classify(s.toLowerCase().replace(/[-_]/g,' ')); if(byNote) return byNote;
      // secours : déduire le tour depuis les noms-placeholder des équipes (avant tirage)
      var nm=''; try{ (c.competitors||[]).forEach(function(x){ nm+=' '+((x.team&&(x.team.displayName||x.team.shortDisplayName||x.team.abbreviation))||''); }); }catch(_e){}
      nm=nm.toUpperCase();
      if(/SF\s*W|SEMIFINAL W/.test(nm)) return {k:7,n:'🏆 Finale'};
      if(/QF\s*W|QUARTERFINAL W/.test(nm)) return {k:5,n:'½ Demi-finales'};
      if(/RD16\s*W|R16\s*W|ROUND OF 16 W/.test(nm)) return {k:4,n:'¼ Quarts de finale'};
      if(/RD32\s*W|R32\s*W|ROUND OF 32 W/.test(nm)) return {k:3,n:'8es de finale'};
      if(/\b[12][A-L]\b|WINNER GROUP|GROUP WINNER|RUNNER|3RD|THIRD/.test(nm)) return {k:2,n:'16es de finale'};
      return null;
    }
    var groups={};
    evs.forEach(function(e){ var ro=roundOf(e); if(!ro) return; (groups[ro.k]=groups[ro.k]||{n:ro.n,items:[]}).items.push(e); });
    var keys=Object.keys(groups).map(Number).sort(function(a,b){return a-b;});
    if(!keys.length){
      box.innerHTML='<div style="color:var(--t3);font-size:11px;text-align:center;padding:14px;line-height:1.6;">🏟 La phase finale n\'est pas encore programmée par ESPN.<br><span style="font-size:10px;">Les affiches (16es → finale) apparaîtront ici dès qu\'elles seront connues.</span></div>';
      return;
    }
    function sc(c){ var s=c&&c.score; if(s==null) return ''; return (typeof s==='object')?(s.displayValue!=null?s.displayValue:s.value):s; }
    // CSS du bracket (injecté une fois)
    if(!document.getElementById('g45brk-css')){
      var stl=document.createElement('style'); stl.id='g45brk-css';
      stl.textContent='.g45brk-wrap{overflow-x:auto;-webkit-overflow-scrolling:touch;padding-bottom:8px;}'
        +'.g45brk{display:flex;align-items:stretch;padding:2px;--brkline:rgba(120,150,220,.38);}'
        +'.g45brk-col{flex:1 1 0;min-width:132px;display:flex;flex-direction:column;padding:0 8px;}'
        +'.g45brk-h{font-size:9px;font-weight:800;text-transform:uppercase;color:#1ed760;text-align:center;letter-spacing:.5px;padding:2px 0 8px;}'
        +'.g45brk-body{flex:1;display:flex;flex-direction:column;}'
        +'.g45brk-slot{flex:1;display:flex;align-items:center;position:relative;min-height:48px;}'
        +'.g45brk-slot>.g45brk-card{width:100%;}'
        +'.g45brk-card{background:rgba(255,255,255,.04);border:1px solid rgba(255,255,255,.09);border-radius:8px;overflow:hidden;cursor:pointer;}'
        +'.g45brk-card:hover{border-color:rgba(30,215,96,.5);}'
        +'.g45brk-r{display:flex;align-items:center;gap:5px;padding:4px 7px;font-size:11px;}'
        +'.g45brk-r+.g45brk-r{border-top:1px solid rgba(255,255,255,.06);}'
        +'.g45brk-r img{width:15px;height:15px;object-fit:contain;flex-shrink:0;border-radius:2px;}'
        +'.g45brk-nm{flex:1;font-weight:600;color:var(--t1);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;}'
        +'.g45brk-sc{font-weight:800;color:var(--t1);min-width:14px;text-align:right;}'
        +'.g45brk-win .g45brk-nm,.g45brk-win .g45brk-sc{color:#1ed760;font-weight:800;}'
        +'.g45brk-dt{font-size:8px;color:#8aa0ff;text-align:center;padding:2px 4px 3px;background:rgba(0,0,0,.18);white-space:nowrap;}'
        +'.g45brk-live{border-left:3px solid #ff4545;}'
        +'.g45brk-tbd{width:100%;height:22px;border:1px dashed rgba(255,255,255,.10);border-radius:6px;opacity:.5;}'
        +'.g45brk-col:not(:last-child) .g45brk-slot::after{content:"";position:absolute;left:100%;width:13px;pointer-events:none;}'
        +'.g45brk-col:not(:last-child) .g45brk-slot:nth-child(odd)::after{top:50%;bottom:0;border-right:2px solid var(--brkline);border-bottom:2px solid var(--brkline);}'
        +'.g45brk-col:not(:last-child) .g45brk-slot:nth-child(even)::after{top:0;bottom:50%;border-right:2px solid var(--brkline);border-top:2px solid var(--brkline);}'
        +'.g45brk-col:not(:first-child) .g45brk-slot::before{content:"";position:absolute;right:100%;width:13px;height:2px;top:50%;background:var(--brkline);pointer-events:none;}';
      document.head.appendChild(stl);
    }
    function card(e){
      var c=(e.competitions&&e.competitions[0])||{}, cps=c.competitors||[];
      var home=cps.filter(function(x){return x.homeAway==='home';})[0]||cps[0]||{};
      var away=cps.filter(function(x){return x.homeAway==='away';})[0]||cps[1]||{};
      var st=(c.status&&c.status.type)||{}, done=st.completed, live=st.state==='in';
      function row(cc){
        var t=(cc&&cc.team)||{}, nm=t.abbreviation||t.shortDisplayName||t.displayName||'—';
        var dn=t.displayName||t.shortDisplayName||t.name||'', mm;
        if((mm=dn.match(/Round of 32 (\d+) Winner/i))) nm='Vainq. 16e #'+mm[1];
        else if((mm=dn.match(/Round of 16 (\d+) Winner/i))) nm='Vainq. 8e #'+mm[1];
        else if((mm=dn.match(/Quarterfinal (\d+) Winner/i))) nm='Vainq. ¼ #'+mm[1];
        else if((mm=dn.match(/Semifinal (\d+) Winner/i))) nm='Vainq. ½ #'+mm[1];
        else if((mm=dn.match(/Semifinal (\d+) Loser/i))) nm='Perd. ½ #'+mm[1];
        else if((mm=dn.match(/Third Place Group ([A-Z\/]+)/i))) nm='3e '+mm[1];
        else if((mm=dn.match(/Group ([A-Z]) Winner/i))) nm='1er '+mm[1];
        else if((mm=dn.match(/Group ([A-Z]) (\d)(?:st|nd|rd|th) Place/i))) nm=mm[2]+'e '+mm[1];
        var logo=(t.logos&&t.logos[0]&&t.logos[0].href)||t.logo||'';
        var win=cc&&cc.winner===true, scv=(done||live)?sc(cc):'';
        return '<div class="g45brk-r'+(win?' g45brk-win':'')+'">'+(logo?'<img src="'+logo+'" onerror="this.style.display=\'none\'">':'<span style="width:15px;display:inline-block;"></span>')+'<span class="g45brk-nm">'+nm+'</span><span class="g45brk-sc">'+scv+'</span></div>';
      }
      var dt=new Date(e.date);
      var dlabel=live?'🔴 EN DIRECT':(done?(isNaN(dt)?'':dt.toLocaleDateString('fr-FR',{day:'2-digit',month:'2-digit'})):(isNaN(dt)?'à venir':dt.toLocaleString('fr-FR',{weekday:'short',day:'2-digit',month:'2-digit',hour:'2-digit',minute:'2-digit'})));
      return '<div class="g45brk-card'+(live?' g45brk-live':'')+'" onclick="g45BrkOpen(\''+e.id+'\',\''+slug+'\')">'+row(home)+row(away)+'<div class="g45brk-dt">'+dlabel+'</div></div>';
    }
    function dedupeSort(items){ var seen={}; return items.filter(function(e){ if(seen[e.id])return false; seen[e.id]=1; return true; }).sort(function(a,b){return new Date(a.date)-new Date(b.date);}); }
    var roundDef=[{k:2,l:'16es'},{k:3,l:'8es'},{k:4,l:'Quarts'},{k:5,l:'Demies'},{k:7,l:'Finale'}];
    var counts={2:16,3:8,4:4,5:2,7:1};
    var ordered=_g45BrkOfficial2026(groups, slug) || _g45BrkBracketOrder(groups); // Mondial : ordre officiel codé en dur ; sinon reconstruction générique
    var colsHtml='';
    roundDef.forEach(function(rd){
      var n=counts[rd.k]||1;
      var ms=(ordered&&ordered[rd.k]) ? ordered[rd.k] : (groups[rd.k]?dedupeSort(groups[rd.k].items):[]);
      var slots='';
      for(var i=0;i<n;i++){ slots+='<div class="g45brk-slot">'+(ms[i]?card(ms[i]):'<div class="g45brk-tbd"></div>')+'</div>'; }
      colsHtml+='<div class="g45brk-col"><div class="g45brk-h">'+rd.l+'</div><div class="g45brk-body">'+slots+'</div></div>';
    });
    var thirdHtml='';
    if(groups[6]){ thirdHtml='<div style="margin-top:12px;max-width:240px;"><div class="g45brk-h" style="text-align:left;">🥉 Match pour la 3e place</div>'+dedupeSort(groups[6].items).map(card).join('')+'</div>'; }
    var html='<div style="display:flex;align-items:center;justify-content:space-between;margin:2px 0 6px;">'
      +'<span style="font-size:9px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;color:#1ed760;">🏟 Phase finale</span>'
      +'<span style="font-size:8px;color:var(--t3);">clique un match pour le détail</span></div>'
      +'<div class="g45brk-wrap"><div class="g45brk">'+colsHtml+'</div></div>'
      +thirdHtml
      +'<div id="g45-brk-detail" style="margin-top:10px;"></div>';
    box.innerHTML=html;
  }catch(e){
    box.innerHTML='<div style="color:#ff6b6b;font-size:11px;text-align:center;padding:12px;">Erreur de chargement de la phase finale.</div>';
  }
}
function g45BrkOpen(eid, slug){
  var det=document.getElementById('g45-brk-detail'); if(!det) return;
  if(det.getAttribute('data-eid')===eid){ det.innerHTML=''; det.removeAttribute('data-eid'); return; }
  det.setAttribute('data-eid',eid); det.innerHTML='';
  try{ _renderSaisonDetail(det, eid, slug||'fifa.world'); }catch(e){ det.innerHTML='<div style="color:var(--t3);font-size:11px;padding:8px;">Détail indisponible.</div>'; }
  try{ det.scrollIntoView({behavior:'smooth',block:'nearest'}); }catch(e){}
}
window.g45ToggleBracket=g45ToggleBracket;
window.g45LoadBracket=g45LoadBracket;
window.g45BrkOpen=g45BrkOpen;

/* ───────────── AUTO-REFRESH des listes Direct/Résultats (scores live en place, sans recharger la page) ───────────── */
function _g45RefreshCtx(){
  var id=window._g45ListId;
  if(id==='g45-res-list') return {id:id, slug:window._g45CalSlug, sport:window._g45CalSport};
  return {id:'g45-live-list', slug:window._g45LiveSlug, sport:window._g45Sport};
}
function _g45StartListRefresh(){
  if(window._g45ListInterval){ clearInterval(window._g45ListInterval); window._g45ListInterval=null; }
  window._g45ListInterval=setInterval(_g45RefreshLiveScores, 30000);
}
async function _g45RefreshLiveScores(){
  if(document.hidden) return; // économie batterie
  var ctx=_g45RefreshCtx();
  var list=document.getElementById(ctx.id);
  if(!list || !ctx.slug){ if(window._g45ListInterval){ clearInterval(window._g45ListInterval); window._g45ListInterval=null; } return; }
  if(!list.querySelector('[data-eid]')) return;
  try{
    var ymd=function(d){ return ''+d.getFullYear()+String(d.getMonth()+1).padStart(2,'0')+String(d.getDate()).padStart(2,'0'); };
    var r=await fetch('https://site.api.espn.com/apis/site/v2/sports/'+ctx.sport+'/'+ctx.slug+'/scoreboard?dates='+ymd(new Date()));
    if(!r.ok) return;
    var data=await r.json(), anyLive=false;
    (data.events||[]).forEach(function(e){
      var row=list.querySelector('[data-eid="'+e.id+'"]'); if(!row) return;
      var comp=(e.competitions&&e.competitions[0])||{}, cps=comp.competitors||[];
      var home=cps.filter(function(c){return c.homeAway==='home';})[0]||cps[0]||{};
      var away=cps.filter(function(c){return c.homeAway==='away';})[0]||cps[1]||{};
      var st=(e.status&&e.status.type&&e.status.type.state)||'';
      var live=st==='in', fin=st==='post'; if(live) anyLive=true;
      var hS=home.score, aS=away.score;
      var sc=row.querySelector('[data-g45score]');
      if(sc){ sc.textContent=((hS!=null&&aS!=null)&&(live||fin))?(hS+' - '+aS):'vs'; sc.style.color=live?'#ff4545':'var(--a)'; }
      var bd=row.querySelector('[data-g45badge]');
      if(bd){
        if(live){ bd.textContent='🔴 '+_g45LiveBadge(e.status, ctx.sport); bd.style.color='#ff4545'; }
        else if(fin){ bd.textContent='Terminé'; bd.style.color='var(--t3)'; }
      }
      try{ row.style.borderLeftColor=live?'#ff4545':'rgba(255,255,255,.1)'; row.style.background=live?'rgba(255,69,69,.07)':'rgba(255,255,255,.03)'; }catch(_e){}
    });
    if(!anyLive){ if(window._g45ListInterval){ clearInterval(window._g45ListInterval); window._g45ListInterval=null; } } // plus de live → on arrête de poller
  }catch(e){}
}

/* ───────────── Re-sync des notifs paris quand les paris changent (wrap de save) ───────────── */
window.toggleNotifBets = (typeof toggleNotifBets!=='undefined') ? toggleNotifBets : window.toggleNotifBets;
window.g45BetTeamNames = (typeof g45BetTeamNames!=='undefined') ? g45BetTeamNames : window.g45BetTeamNames;
(function(){
  var _bt=null;
  window._g45DebouncedBetSync=function(){
    if(_bt) clearTimeout(_bt);
    _bt=setTimeout(function(){
      try{ var p=g45NotifPrefs(); if(p.enabled && p.bets!==false && typeof g45SyncNotifs==='function') g45SyncNotifs(); }catch(e){}
    }, 1500);
  };
  if(typeof save==='function' && !save._g45betw){
    var _os=save;
    save=function(){ var r=_os.apply(this,arguments); try{ window._g45DebouncedBetSync(); }catch(e){} try{ if(typeof _g45PushBetsGithub==='function') _g45PushBetsGithub(); }catch(e){} return r; };
    save._g45betw=true;
  }
})();

/* ═══════════ SYNCHRO PARIS via GITHUB (Antoine uniquement — détecté par la présence du token GitHub) ═══════════
   Remplace Dropbox POUR ANTOINE sans toucher au mode Dropbox (conservé pour Bruno/JP).
   Écrit/lit données/bets_antoine.json directement via l'API GitHub (même mécanisme que les stats joueurs).
   Réservé à Antoine car lui seul possède gones45_github_token en localStorage. */
var G45_BETS_FILE='données/bets_antoine.json';
function _g45BetSyncOn(){
  if(!localStorage.getItem('gones45_github_token')) return false;       // seul Antoine a le token GitHub
  return localStorage.getItem('g45_github_betsync')!=='0';              // ON par défaut, coupable via le flag
}
function g45ToggleGithubBetSync(){
  var on=_g45BetSyncOn();
  localStorage.setItem('g45_github_betsync', on?'0':'1');
  alert('Synchro paris GitHub : '+(on?'DÉSACTIVÉE':'ACTIVÉE'));
  if(!on){ try{ _g45PushBetsGithub(true); }catch(e){} }
}
/* ── Chiffrement (AES-GCM) : tes paris sont brouillés avant d'aller sur GitHub ── */
/* Clé de chiffrement : par défaut = ton TOKEN GITHUB (déjà présent sur tes appareils pour les stats).
   → rien de plus à retenir. Tu peux quand même forcer un mot de passe séparé via g45SetBetsPass(). */
function _g45BetsPass(){ return localStorage.getItem('g45_bets_pass') || localStorage.getItem('gones45_github_token') || null; }
function g45SetBetsPass(){
  var p=prompt('Mot de passe de chiffrement de tes paris (le MÊME sur tous tes appareils) :');
  if(p===null) return;
  if(!p){ alert('Mot de passe vide — annulé.'); return; }
  localStorage.setItem('g45_bets_pass', p);
  alert('Mot de passe enregistré sur cet appareil. Mets le MÊME sur ton autre appareil.');
  try{ _g45PushBetsGithub(true); }catch(e){}
}
async function _g45CryptoKey(pass, salt){
  var km=await crypto.subtle.importKey('raw', new TextEncoder().encode(pass), {name:'PBKDF2'}, false, ['deriveKey']);
  return crypto.subtle.deriveKey({name:'PBKDF2', salt:salt, iterations:120000, hash:'SHA-256'}, km, {name:'AES-GCM', length:256}, false, ['encrypt','decrypt']);
}
function _g45b64(buf){ var b=new Uint8Array(buf),s=''; for(var i=0;i<b.length;i++) s+=String.fromCharCode(b[i]); return btoa(s); }
function _g45unb64(str){ var bin=atob(str),a=new Uint8Array(bin.length); for(var i=0;i<bin.length;i++) a[i]=bin.charCodeAt(i); return a; }
async function _g45EncryptState(obj, pass){
  var salt=crypto.getRandomValues(new Uint8Array(16)), iv=crypto.getRandomValues(new Uint8Array(12));
  var key=await _g45CryptoKey(pass, salt);
  var ct=await crypto.subtle.encrypt({name:'AES-GCM', iv:iv}, key, new TextEncoder().encode(JSON.stringify(obj)));
  var out=new Uint8Array(16+12+ct.byteLength); out.set(salt,0); out.set(iv,16); out.set(new Uint8Array(ct),28);
  return _g45b64(out);
}
async function _g45DecryptState(b64, pass){
  var buf=_g45unb64(b64), salt=buf.slice(0,16), iv=buf.slice(16,28), ct=buf.slice(28);
  var key=await _g45CryptoKey(pass, salt);
  var pt=await crypto.subtle.decrypt({name:'AES-GCM', iv:iv}, key, ct);
  return JSON.parse(new TextDecoder().decode(pt));
}
async function _gh_getBets(){
  var token=localStorage.getItem('gones45_github_token'); if(!token) return null;
  try{
    var r=await fetch('https://api.github.com/repos/'+GITHUB_OWNER+'/'+GITHUB_REPO+'/contents/'+G45_BETS_FILE,{headers:{'Authorization':'token '+token,'Accept':'application/vnd.github.v3+json'}});
    if(r.status===404) return {data:null, sha:null};
    if(!r.ok) return null;
    var d=await r.json();
    var json=decodeURIComponent(escape(atob((d.content||'').split('\n').join(''))));
    return {data:JSON.parse(json), sha:d.sha};
  }catch(e){ console.warn('gh getBets', e); return null; }
}
async function _gh_saveBets(payload, sha){
  var token=localStorage.getItem('gones45_github_token'); if(!token) return false;
  try{
    var body={message:'Sync paris Antoine '+new Date().toISOString(), content:btoa(unescape(encodeURIComponent(JSON.stringify(payload))))};
    if(sha) body.sha=sha;
    var r=await fetch('https://api.github.com/repos/'+GITHUB_OWNER+'/'+GITHUB_REPO+'/contents/'+G45_BETS_FILE,{method:'PUT',headers:{'Authorization':'token '+token,'Content-Type':'application/json','Accept':'application/vnd.github.v3+json'},body:JSON.stringify(body)});
    if(r.ok){ try{ var rd=await r.json(); return (rd.content&&rd.content.sha)||true; }catch(e){ return true; } }
    return false;
  }catch(e){ console.warn('gh saveBets', e); return false; }
}
/* PUSH (débounce) : écrit l'état complet des paris sur GitHub avec un timestamp */
var _g45BetPushT=null;
function _g45PushBetsGithub(immediate){
  if(!_g45BetSyncOn()) return;
  if(_g45BetPushT) clearTimeout(_g45BetPushT);
  var run=async function(){
    try{
      var pass=_g45BetsPass();
      if(!pass){ console.warn('⚠️ Synchro paris : pas de clé. Mets ton token GitHub dans les réglages (ou g45SetBetsPass pour un mot de passe séparé).'); return; }
      var enc=await _g45EncryptState(state, pass);
      var cur=await _gh_getBets();            // récupère le sha courant (évite les conflits)
      var sha=cur?cur.sha:null;
      var ts=Date.now();
      var ok=await _gh_saveBets({ts:ts, enc:enc}, sha);
      if(ok){ localStorage.setItem('g45_betsync_ts', String(ts)); console.log('✅ paris poussés (chiffrés) sur GitHub'); }
    }catch(e){ console.warn('push bets', e); }
  };
  if(immediate){ run(); } else { _g45BetPushT=setTimeout(run, 2500); }
}
/* PULL (au démarrage) : si GitHub est plus récent que le local, on charge et on recharge la page */
async function _g45PullBetsGithub(){
  if(!_g45BetSyncOn()) return;
  try{
    var res=await _gh_getBets();
    if(!res || !res.data || (!res.data.enc && !res.data.state)){ _g45PushBetsGithub(true); return; } // 1ère fois : on initialise le fichier
    var remoteTs=res.data.ts||0;
    var localTs=parseInt(localStorage.getItem('g45_betsync_ts')||'0',10);
    if(remoteTs>localTs){
      var st=null;
      if(res.data.enc){
        var pass=_g45BetsPass();
        if(!pass){ console.warn('⚠️ Paris chiffrés mais pas de clé sur cet appareil. Mets ton token GitHub (le même que sur ton autre appareil).'); return; }
        try{ st=await _g45DecryptState(res.data.enc, pass); }
        catch(e){ console.warn('⚠️ Déchiffrement échoué (mauvais mot de passe ?). Sync annulée pour ne rien écraser.'); return; }
      } else { st=res.data.state; } // ancien format en clair (ne devrait pas exister)
      if(!st) return;
      if(!st.bkColors) st.bkColors={};
      localStorage.setItem('g45v5', JSON.stringify(st));
      localStorage.setItem('g45_betsync_ts', String(remoteTs));
      console.log('⬇️ paris chargés depuis GitHub (plus récents) — rechargement…');
      location.reload();
    } else if(remoteTs<localTs){
      _g45PushBetsGithub(true); // local plus récent → on pousse
    }
  }catch(e){ console.warn('pull bets', e); }
}
/* Démarrage : pull une fois l'app initialisée */
(function(){
  function go(){ setTimeout(_g45PullBetsGithub, 1200); }
  if(document.readyState==='loading') document.addEventListener('DOMContentLoaded', go); else go();
})();

/* ═════════ FICHE ÉQUIPE — Onglet 📰 News (Google News RSS via proxy, 0 quota, 0 D1/KV) ═════════ */
var _G45_WORKER='https://fd-proxy.touraine-antoine.workers.dev/';
function _g45HostOf(u){ try{ return new URL(u).hostname.replace(/^www\./,''); }catch(e){ return ''; } }
function _g45Norm(s){ return (''+s).toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,''); }
/* Les liens Bing News sont des redirections (bing.com/news/apiclick?url=...) → on extrait la vraie URL */
function _g45Unwrap(link){
  try{ var u=new URL(link); if(/(^|\.)bing\.com$/i.test(u.hostname)){ var real=u.searchParams.get('url'); if(real) return real; } }catch(e){}
  return link;
}
/* Parse un flux RSS générique → [{title, link, desc, ts, src}] */
function _g45ParseRssItems(xml, limit){
  var doc=new DOMParser().parseFromString(xml,'text/xml');
  var nodes=doc.querySelectorAll('item'); var out=[];
  for(var i=0;i<nodes.length && out.length<(limit||60);i++){
    var it=nodes[i];
    var title=((it.querySelector('title')&&it.querySelector('title').textContent)||'').trim();
    var link=_g45Unwrap(((it.querySelector('link')&&it.querySelector('link').textContent)||'').trim());
    var pub=((it.querySelector('pubDate')&&it.querySelector('pubDate').textContent)||'').trim();
    var desc=((it.querySelector('description')&&it.querySelector('description').textContent)||'');
    if(!title) continue;
    out.push({title:title, link:link, desc:desc, ts:(pub?Date.parse(pub)||0:0), src:_g45HostOf(link)});
  }
  return out;
}
/* Nom court ambigu → requête officielle (lève l'ambiguïté ville/club pour Bing) */
var _G45_TEAM_ALIAS={
  'lyon':'"Olympique Lyonnais"','ol':'"Olympique Lyonnais"',
  'psg':'"Paris Saint-Germain"','paris':'"Paris Saint-Germain"','paris sg':'"Paris Saint-Germain"',
  'om':'"Olympique de Marseille"','marseille':'"Olympique de Marseille"',
  'asse':'"AS Saint-Étienne"','saint-etienne':'"AS Saint-Étienne"','saint etienne':'"AS Saint-Étienne"',
  'lille':'"LOSC Lille"','losc':'"LOSC Lille"',
  'rennes':'"Stade Rennais"','nice':'"OGC Nice"','nantes':'"FC Nantes"','lens':'"RC Lens"',
  'monaco':'"AS Monaco"','strasbourg':'"RC Strasbourg"','bordeaux':'"Girondins Bordeaux"',
  'france':'équipe de France football','inter':'"Inter Milan"','milan':'"Inter Milan"',
  'arsenal':'"Arsenal FC"','psv':'"PSV Eindhoven"','bayern':'"Bayern Munich"','madrid':'"Real Madrid"'
};
/* Construit la requête de recherche : nom officiel si connu, sinon nom (+ sport si nom court ambigu) */
function _g45TeamQuery(nom){
  var alias=_G45_TEAM_ALIAS[_g45Norm(nom)];
  if(alias) return alias;
  var sw=_g45SportWord(nom);
  var multiWord=/\s/.test((nom||'').trim()); // nom déjà complet (≥2 mots) → pas besoin du mot sport
  return '"'+nom+'"'+((sw && !multiWord)?(' '+sw):'');
}
/* Déduit un mot-clé de sport (français) à partir du sport de l'équipe → désambiguïse la recherche */
function _g45SportWord(nom){
  var u=(typeof state!=='undefined'&&state.u)?state.u.find(function(x){return x&&x.n===nom;}):null;
  var s=_g45Norm((u&&u.sport)||'');
  if(s.indexOf('foot')>=0) return 'football';
  if(s.indexOf('rugby')>=0) return 'rugby';
  if(s.indexOf('tennis')>=0) return 'tennis';
  if(s.indexOf('hockey')>=0||s.indexOf('nhl')>=0) return 'hockey';
  if(s.indexOf('baseball')>=0||s.indexOf('mlb')>=0) return 'baseball';
  if(s.indexOf('basket')>=0||s.indexOf('nba')>=0) return 'basket';
  if(s.indexOf('f1')>=0||s.indexOf('formule')>=0||s.indexOf('formula')>=0) return 'Formule 1';
  return '';
}
/* Source 1 : Bing News (recherche par nom officiel + sport pour la pertinence, FR) */
async function _g45BingFetch(nom){
  var q=_g45TeamQuery(nom);
  var path='/news/search?q='+encodeURIComponent(q)+'&format=rss&setmkt=fr-FR&setlang=fr';
  var r=await fetch(_G45_WORKER+'?host=bing&path='+encodeURIComponent(path));
  if(!r.ok) throw new Error('HTTP '+r.status);
  var items=_g45ParseRssItems(await r.text(),15);
  return items.slice(0,15);
}
/* Mots-clés courts pour filtrer les flux RSS (les titres disent "Lyon", pas "Olympique Lyonnais") */
var _G45_RSS_KW={
  'olympique lyonnais':['lyon'],'lyon':['lyon'],'ol':['lyon'],
  'paris saint-germain':['psg','paris saint'],'psg':['psg','paris saint'],'paris':['psg','paris saint'],
  'olympique de marseille':['marseille'],'om':['marseille'],'marseille':['marseille'],
  'as saint-etienne':['saint-etienne','asse'],'saint-etienne':['saint-etienne','asse'],
  'losc lille':['lille'],'lille':['lille'],'stade rennais':['rennes'],'rennes':['rennes'],
  'ogc nice':['nice'],'nice':['nice'],'fc nantes':['nantes'],'nantes':['nantes'],
  'rc lens':['lens'],'lens':['lens'],'as monaco':['monaco'],'monaco':['monaco'],
  'inter milan':['inter milan','inter'],'inter':['inter milan','inter'],
  'real madrid':['real madrid','real'],'bayern munich':['bayern'],'bayern':['bayern'],
  'arsenal fc':['arsenal'],'arsenal':['arsenal'],'psv eindhoven':['psv'],'psv':['psv'],
  'equipe de france football':['equipe de france','bleus'],'france':['equipe de france','bleus'],
  'palmeiras':['palmeiras']
};
function _g45RssKeywords(nom){
  var n=_g45Norm(nom);
  if(_G45_RSS_KW[n]) return _G45_RSS_KW[n];
  var generic={olympique:1,real:1,inter:1,fc:1,ac:1,as:1,sc:1,rc:1,club:1,de:1,la:1,le:1,les:1,du:1,united:1,city:1,football:1,athletic:1,sporting:1,stade:1};
  var words=n.split(/[^a-z0-9]+/).filter(function(w){return w.length>=4 && !generic[w];});
  words.push(n);
  return words;
}
/* Source 2 (repli) : flux RSS de médias sportifs FR, filtrés par mots-clés d'équipe */
function _g45FeedList(sw){
  var lm={football:'football',rugby:'rugby',tennis:'tennis'};
  var rmc={football:'football',rugby:'rugby',tennis:'tennis',basket:'basket'};
  var L=[];
  L.push({host:'www.lemonde.fr', path:'/'+(lm[sw]||'sport')+'/rss_full.xml'});
  L.push({host:'www.francetvinfo.fr', path:'/sports.rss'});
  if(rmc[sw]) L.push({host:'rmcsport.bfmtv.com', path:'/rss/'+rmc[sw]+'/'});
  return L;
}
async function _g45FeedFetch(nom){
  var sw=_g45SportWord(nom);
  var feeds=_g45FeedList(sw);
  var kws=_g45RssKeywords(nom);
  for(var i=0;i<feeds.length;i++){
    try{
      var f=feeds[i];
      var r=await fetch(_G45_WORKER+'?host=rss&rsshost='+encodeURIComponent(f.host)+'&path='+encodeURIComponent(f.path));
      if(!r.ok) continue;
      var all=_g45ParseRssItems(await r.text(),80);
      if(!all.length) continue;
      var hit=all.filter(function(n){ var t=_g45Norm(n.title+' '+n.desc); return kws.some(function(k){ return k && t.indexOf(k)>=0; }); });
      if(hit.length) return hit.slice(0,15);
    }catch(e){}
  }
  return [];
}
function _g45NewsAgo(ts){
  if(!ts) return '';
  var s=Math.floor((Date.now()-ts)/1000); if(s<0)s=0;
  if(s<60) return "à l'instant";
  var m=Math.floor(s/60); if(m<60) return 'il y a '+m+' min';
  var h=Math.floor(m/60); if(h<24) return 'il y a '+h+' h';
  var j=Math.floor(h/24); return 'il y a '+j+' j';
}
/* Injecte (une seule fois) le bouton d'onglet + le panneau dans la fiche déjà ouverte */
function _g45EnsureNewsTab(){
  var anyTab=document.querySelector('.itab');
  var anyPanel=document.getElementById('ip-bilan');
  if(!anyTab||!anyTab.parentNode||!anyPanel||!anyPanel.parentNode) return;
  if(!document.getElementById('ip-news')){
    var pan=document.createElement('div'); pan.id='ip-news'; pan.className='ipanel'; pan.style.display='none';
    anyPanel.parentNode.appendChild(pan);
  }
  if(!document.getElementById('itab-news')){
    var btn=document.createElement('button'); btn.id='itab-news'; btn.className='itab';
    btn.innerHTML='📰 News';
    btn.setAttribute('onclick','_g45OpenNewsTab(this)');
    anyTab.parentNode.appendChild(btn);
  }
}
function _g45OpenNewsTab(btn){
  try{ swInner('news', btn); }catch(e){}
  window._currentInnerTab='news';
  loadTeamNews(window._currentTeam);
}
window._g45OpenNewsTab=_g45OpenNewsTab;
async function loadTeamNews(nom, force){
  var el=document.getElementById('ip-news'); if(!el) return;
  if(!nom){ el.innerHTML='<div style="padding:14px;color:var(--t3);font-size:11px;">Aucune équipe sélectionnée.</div>'; return; }
  var ck='g45news7_'+nom, items=null, cachedTs=0;
  if(!force){
    try{ var raw=localStorage.getItem(ck); if(raw){ var o=JSON.parse(raw); if(o&&o.items&&(Date.now()-(o.t||0))<20*60000){ items=o.items; cachedTs=o.t; } } }catch(e){}
  }
  var header='<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:8px;">'
    +'<div style="font-size:10px;font-weight:700;color:#7aaaff;letter-spacing:.5px;text-transform:uppercase;">📰 Dernières infos — '+nom+'</div>'
    +'<button onclick="loadTeamNews(window._currentTeam,true)" style="background:none;border:1px solid rgba(77,132,255,.3);border-radius:6px;color:#7aaaff;font-size:10px;font-weight:700;padding:3px 8px;cursor:pointer;">↻</button>'
    +'</div>';
  if(!items){
    el.innerHTML=header+'<div style="display:flex;align-items:center;gap:8px;color:#4f5d88;font-size:12px;padding:6px 2px;"><div style="width:12px;height:12px;border:2px solid rgba(77,132,255,.2);border-top-color:#4d84ff;border-radius:50%;animation:spin .8s linear infinite;flex-shrink:0;"></div>Recherche des news…</div>';
    try{
      items=[]; var errMsg=null;
      // 1) L'Équipe (fiable, foot surtout). 2) si vide → repli Bing (toutes équipes, FR).
      try{ items=await _g45FeedFetch(nom); }catch(eL){ errMsg='Flux RSS '+(eL&&eL.message||''); items=[]; }
      if(!items.length){ try{ items=await _g45BingFetch(nom); }catch(eB){ errMsg=(errMsg?errMsg+' · ':'')+'Bing '+(eB&&eB.message||''); } }
      if(!items.length && errMsg){
        el.innerHTML=header+'<div style="padding:12px;color:var(--t3);font-size:11px;">⚠️ News indisponibles ('+errMsg+'). Réessaie avec ↻.</div>';
        return;
      }
      // On ne met en cache QUE de vrais résultats.
      if(items.length){ try{ localStorage.setItem(ck, JSON.stringify({t:Date.now(), items:items})); }catch(e){} }
      cachedTs=Date.now();
    }catch(e){
      el.innerHTML=header+'<div style="padding:12px;color:var(--t3);font-size:11px;">⚠️ News indisponibles pour le moment. Réessaie avec ↻.</div>';
      return;
    }
  }
  if(!items.length){ el.innerHTML=header+'<div style="padding:12px;color:var(--t3);font-size:11px;">Aucune actualité trouvée pour « '+nom+' ».</div>'; return; }
  var html=header;
  if(cachedTs) html+='<div style="font-size:9px;color:var(--t3);margin-bottom:8px;">Mis à jour '+_g45NewsAgo(cachedTs)+' · gratuit, 0 quota</div>';
  items.forEach(function(n){
    var when=_g45NewsAgo(n.ts);
    html+='<a href="'+n.link+'" target="_blank" rel="noopener" style="display:block;text-decoration:none;background:rgba(255,255,255,.03);border:1px solid rgba(255,255,255,.06);border-radius:10px;padding:10px 12px;margin-bottom:8px;">'
      +'<div style="font-size:12.5px;color:var(--t1);font-weight:600;line-height:1.4;">'+n.title+'</div>'
      +'<div style="font-size:10px;color:var(--t3);margin-top:5px;display:flex;gap:8px;flex-wrap:wrap;">'+(n.src?'<span style="color:#7aaaff;font-weight:700;">'+n.src+'</span>':'')+(when?'<span>'+when+'</span>':'')+'</div>'
      +'</a>';
  });
  el.innerHTML=html;
}
window.loadTeamNews=loadTeamNews;
