  var defIdx=-1;
  comps.forEach(function(c,i){ var t=(c.type&&(c.type.abbreviation||c.type.text))||''; if(/race/i.test(t)&&!/sprint/i.test(t)) defIdx=i; });
  if(defIdx<0) defIdx=comps.length-1;
  window._g45F1Eid=eid;
